// Stage 3: Fan out one item per job for parallel agent processing
// Mode: Run Once for All Items
//
// Reads from Data Loader sub-workflow output (returns { ready_jobs, master_doc, config }).
// Bundles master_doc AND config into each per-job item â€” preserves the original
// flat structure (job fields at top level) for compatibility with existing agents.
const dataLoaderOutput = $('Data Loader').first()?.json;
// Defensive validation
if (!dataLoaderOutput) {
  throw new Error('[Fan Out Plans] Data Loader output missing â€” check node name and Execute Workflow wiring');
}
const rawJobs = dataLoaderOutput.ready_jobs;
const masterDoc = dataLoaderOutput.master_doc;
const config = dataLoaderOutput.config;
if (!Array.isArray(rawJobs) || rawJobs.length === 0) {
  console.log('[Fan Out Plans] No ready jobs to process â€” exiting cleanly');
  return [];
}
if (!masterDoc || typeof masterDoc !== 'string' || masterDoc.length < 100) {
  throw new Error(`[Fan Out Plans] master_doc missing or too short (${masterDoc?.length || 0} chars)`);
}
if (!config || typeof config !== 'object') {
  throw new Error('[Fan Out Plans] config missing or invalid from Data Loader output');
}
// Normalize: if Data Loader returned jobs wrapped as {json: {...}}, unwrap them
const jobs = rawJobs.map(j => (j && typeof j === 'object' && 'json' in j) ? j.json : j);
console.log(`[Fan Out Plans] Setup complete:`);
console.log(`  - Jobs ready:    ${jobs.length}`);
console.log(`  - Master doc:    ${masterDoc.length} chars`);
console.log(`  - Config keys:   ${Object.keys(config).length}`);
console.log(`[Fan Out Plans] Fanning out ${jobs.length} job(s)`);
// Bundle master_doc AND config into each job item.
// Job fields at top level (preserves original structure for downstream agents).
const fanned = jobs.map((job, idx) => ({
  json: {
    ...job,                 // job fields at top level
    master_doc: masterDoc,
    config,
    fanout_index: idx + 1,
    fanout_total: jobs.length
  }
}));
return fanned;

// Log Job Result â€” per-job. Reads .all() from each agent node, index-aligned.
// Anchor = Resume Scorer (direct input). Job identity from Fan Out Plans by index.
const scored = $('Resume Scorer').all();
if (!scored.length) return [];

const fanItems = $('Fan Out Plans').all();
const allOf = (n) => { try { return $(n).all(); } catch { console.log(`[Log Job Result] '${n}' not found`); return []; } };
const pick = (arr, i) => (arr[i] ? arr[i].json : null);

const dl = $('Data Loader').first().json;
const pricing = dl.pricing || {};
const runId = dl.run_id || '';
const config = dl.config || {};
const coverEnabled = String(config.enable_cover_letter_drafter).toLowerCase().trim() === 'true';
const promptLoader = (() => { try { return $('Prompt Loader').first()?.json; } catch { return null; } })();
const promptWarnings = promptLoader?.prompt_warnings || [];

const computeCost = (u, r) => !r ? 0 :
  (u.input_tokens || 0)/1e6*(r.input_per_million||0) +
  (u.output_tokens||0)/1e6*(r.output_per_million||0) +
  (u.cached_input_tokens||0)/1e6*(r.cached_input_per_million||0) +
  (u.cache_write_tokens||0)/1e6*(r.cache_write_per_million||0);

const rb = allOf('Resume Builder');
const clb = allOf('Cover Letter Builder');
const rv = allOf('Resume Verifier');
const clv = allOf('Cover Letter Verifier');
const cr = allOf('Critic');
const sc = allOf('Resume Scorer');

const results = [];

for (let i = 0; i < scored.length; i++) {
  const fanOut = pick(fanItems, i) || {};
  const agent1 = pick(rb, i);
  const agent2 = pick(clb, i);
  const agent3 = pick(rv, i);
  const agent4 = pick(clv, i);
  const agent5 = pick(cr, i);
  const agent7 = pick(sc, i);

  const missingPricing = new Set();
  const costFor = (a, id) => {
    if (!a) return 0;
    const m = a.model_used || '';
    if (m === 'skipped' || m === 'crash' || m === 'unknown') return 0;
    const r = pricing[m] || null;
    if (!r && m) missingPricing.add(`${id}:${m}`);
    return computeCost({
      input_tokens: a.tokens?.input || 0,
      output_tokens: a.tokens?.output || 0,
      cached_input_tokens: a.cached_input_tokens || 0,
      cache_write_tokens: a.cache_write_tokens || 0
    }, r);
  };

  const finalResumeMarkdown = agent1?.result?.resume_markdown || '';
  const cost1 = costFor(agent1, 'agent_1');
  const cost2 = costFor(agent2, 'agent_2');
  const cost3 = costFor(agent3, 'agent_3');
  const cost4 = costFor(agent4, 'agent_4');
  const cost5 = costFor(agent5, 'agent_5');
  const cost7 = costFor(agent7, 'agent_7');

  const errorLog = [];
  const addErr = (id, a) => { if (a && a.success === false && a.cascaded !== true) errorLog.push(`${id}:${a.error?.category || 'unknown'}`); };
  addErr('agent_1', agent1); addErr('agent_2', agent2); addErr('agent_3', agent3);
  addErr('agent_4', agent4); addErr('agent_5', agent5); addErr('agent_7', agent7);
  for (const w of promptWarnings) errorLog.push(`prompt_loader:${w.agent||'unknown'}:${w.issue||'unknown'}`);
  for (const e of missingPricing) errorLog.push(`data_loader:missing_pricing:${e}`);

  const hasAnyFailure = [agent1,agent2,agent3,agent4,agent5,agent7].some(a => a && a.success === false);
  const hasInsufficientCredit = [agent1,agent2,agent3,agent4,agent5,agent7].some(a => a && a.success === false && a.cascaded !== true && a.error?.category === 'insufficient_credit');
  // Core agents whose failure makes the JOB fail (resume, verifier, critic).
// Cover letter / cover verifier / scorer failures do NOT fail the job (per rule a/b).
const coreAgents = [agent1, agent3, agent5];
const coreCredit = coreAgents.some(a => a && a.success === false && a.cascaded !== true && a.error?.category === 'insufficient_credit');
const coreFailure = coreAgents.some(a => a && a.success === false);

const processed_status = coreCredit ? 'insufficient_credit' : (coreFailure ? 'error' : 'done');

  const discoveryCost = Number(fanOut?.discovery_cost_usd) || 0;
  const discoveryTokensIn = Number(fanOut?.discovery_tokens_in) || 0;
  const discoveryTokensOut = Number(fanOut?.discovery_tokens_out) || 0;

  const result = {
    application_run_id: runId,
    job: {
      job_id: fanOut?.job_id || '', company: fanOut?.company || 'unknown', title: fanOut?.title || 'unknown',
      url: fanOut?.url || '', location: fanOut?.location || '', description_html: fanOut?.description_html || '',
      posted_at: fanOut?.posted_at || '', discovered_at: fanOut?.discovered_at || '',
      resume_folder_url: fanOut?.resume_folder_url || '', fanout_index: fanOut?.fanout_index, fanout_total: fanOut?.fanout_total
    },
    resume: {
      success: agent1?.success || false, cascaded: agent1?.cascaded || false,
      markdown: finalResumeMarkdown, markdown_chars: finalResumeMarkdown.length, refined: false,
      original_markdown: agent1?.result?.resume_markdown || '',
      tokens: agent1?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent1?.cached_input_tokens || 0,
      cache_write_tokens: agent1?.cache_write_tokens || 0, cost: cost1,
      model_used: agent1?.model_used || 'unknown', provider_used: agent1?.provider_used || 'unknown',
      errors: agent1?.errors || [], error: agent1?.error || null
    },
    cover_letter: {
      ran: coverEnabled, success: agent2?.success || false, cascaded: agent2?.cascaded || false,
      markdown: agent2?.result?.cover_letter_markdown || '', markdown_chars: agent2?.result?.cover_letter_markdown?.length || 0,
      tokens: agent2?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent2?.cached_input_tokens || 0,
      cache_write_tokens: agent2?.cache_write_tokens || 0, cost: cost2,
      model_used: agent2?.model_used || 'unknown', provider_used: agent2?.provider_used || 'unknown',
      errors: agent2?.errors || [], error: agent2?.error || null
    },
    verifier: {
      success: agent3?.success || false, cascaded: agent3?.cascaded || false,
      verdict: agent3?.result?.verdict || 'unknown', summary: agent3?.result?.summary || '',
      claim_count: agent3?.result?.claim_count || 0, supported_count: agent3?.result?.supported_count || 0,
      unsupported_count: agent3?.result?.unsupported_count || 0, issues: agent3?.result?.issues || [],
      tokens: agent3?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent3?.cached_input_tokens || 0,
      cache_write_tokens: agent3?.cache_write_tokens || 0, cost: cost3,
      model_used: agent3?.model_used || 'unknown', provider_used: agent3?.provider_used || 'unknown',
      errors: agent3?.errors || [], error: agent3?.error || null
    },
    cover_verifier: {
      ran: coverEnabled, success: agent4?.success || false, cascaded: agent4?.cascaded || false,
      verdict: agent4?.result?.verdict || 'unknown', summary: agent4?.result?.summary || '',
      claim_count: agent4?.result?.claim_count || 0, supported_count: agent4?.result?.supported_count || 0,
      unsupported_count: agent4?.result?.unsupported_count || 0, issues: agent4?.result?.issues || [],
      tokens: agent4?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent4?.cached_input_tokens || 0,
      cache_write_tokens: agent4?.cache_write_tokens || 0, cost: cost4,
      model_used: agent4?.model_used || 'unknown', provider_used: agent4?.provider_used || 'unknown',
      errors: agent4?.errors || [], error: agent4?.error || null
    },
    critic: {
      success: agent5?.success || false, cascaded: agent5?.cascaded || false,
      summary: agent5?.summary || '', issues: agent5?.issues || [], preserve: agent5?.preserve || [],
      total_issues: agent5?.total_issues || 0, critical_count: agent5?.critical_count || 0,
      major_count: agent5?.major_count || 0, minor_count: agent5?.minor_count || 0,
      tokens: agent5?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent5?.cached_input_tokens || 0,
      cache_write_tokens: agent5?.cache_write_tokens || 0, cost: cost5,
      model_used: agent5?.model_used || 'unknown', provider_used: agent5?.provider_used || 'unknown',
      errors: agent5?.errors || [], error: agent5?.error || null
    },
    scorer: {
      success: agent7?.success || false, cascaded: agent7?.cascaded || false,
      overall_score: (typeof agent7?.overall_score === 'number') ? agent7.overall_score : null,
      recommendation: agent7?.recommendation || 'unknown', dimensions: agent7?.dimensions || {},
      strengths: agent7?.strengths || [], gaps: agent7?.gaps || [],
      rationale: agent7?.rationale || agent7?.score_rationale || '',
      strengths_text: agent7?.strengths_text || '', gaps_text: agent7?.gaps_text || '',
      score_rationale: agent7?.score_rationale || agent7?.rationale || '',
      tokens: agent7?.tokens || { input: 0, output: 0 }, cached_input_tokens: agent7?.cached_input_tokens || 0,
      cache_write_tokens: agent7?.cache_write_tokens || 0, cost: cost7,
      model_used: agent7?.model_used || 'unknown', provider_used: agent7?.provider_used || 'unknown',
      errors: agent7?.errors || [], error: agent7?.error || null
    },
    application_cost: cost1+cost2+cost3+cost4+cost5+cost7,
    application_tokens: {
      input: (agent1?.tokens?.input||0)+(agent2?.tokens?.input||0)+(agent3?.tokens?.input||0)+(agent4?.tokens?.input||0)+(agent5?.tokens?.input||0)+(agent7?.tokens?.input||0),
      output: (agent1?.tokens?.output||0)+(agent2?.tokens?.output||0)+(agent3?.tokens?.output||0)+(agent4?.tokens?.output||0)+(agent5?.tokens?.output||0)+(agent7?.tokens?.output||0)
    },
    discovery_cost: discoveryCost,
    discovery_tokens: { input: discoveryTokensIn, output: discoveryTokensOut },
    total_cost: discoveryCost+cost1+cost2+cost3+cost4+cost5+cost7,
    total_tokens: {
      input: discoveryTokensIn+(agent1?.tokens?.input||0)+(agent2?.tokens?.input||0)+(agent3?.tokens?.input||0)+(agent4?.tokens?.input||0)+(agent5?.tokens?.input||0)+(agent7?.tokens?.input||0),
      output: discoveryTokensOut+(agent1?.tokens?.output||0)+(agent2?.tokens?.output||0)+(agent3?.tokens?.output||0)+(agent4?.tokens?.output||0)+(agent5?.tokens?.output||0)+(agent7?.tokens?.output||0)
    },
    error_log: errorLog,
    processed_status: processed_status,
    credit_event: hasInsufficientCredit
  };

  console.log(`[Log Job Result] Job ${result.job.fanout_index}/${result.job.fanout_total} id=${result.job.job_id} status=${result.processed_status} score=${result.scorer.overall_score} $${result.total_cost.toFixed(4)}`);
  results.push({ json: result });
}

return results;

// Resolve Cover Letter: convergence point for the cover-letter branch.
// Mirrors Resolve Resume â€” keeps Merge Branches' positional combine aligned whether
// Agent 2/4 ran or the branch was gated off by enable_cover_letter_drafter.
const config = $('Data Loader').first().json.config || {};
const coverEnabled = String(config.enable_cover_letter_drafter).toLowerCase().trim() === 'true';

// Enabled path: input is Agent 4 (Cover Letter Verifier) â€” pass through unchanged so the
// merged item is byte-identical to today. Disabled path: emit a marker.
return coverEnabled
  ? { json: $input.item.json }
  : { json: { cover_letter_disabled: true } };
